6	/// Auto-connection manager, combining autoconnect matcher and strategy from the config.
7	#[derive(Clone, Copy)]
8	pub(crate) struct AutoConnect {
9	    zid: ZenohIdProto,
10	    matcher: WhatAmIMatcher,
11	    strategy: TargetDependentValue<AutoConnectStrategy>,
12	}
13	
14	impl AutoConnect {
15	    /// Builds an `AutoConnect` from multicast config.
16	    pub(crate) fn multicast(config: &Config, what: WhatAmI, zid: ZenohIdProto) -> Self {
17	        Self {
18	            zid,
19	            matcher: *unwrap_or_default!(config.scouting().multicast().autoconnect().get(what)),
20	            strategy: *unwrap_or_default!(config
21	                .scouting()
22	                .multicast()
23	                .autoconnect_strategy()
24	                .get(what)),
25	        }
26	    }
27	
28	    /// Builds an `AutoConnect` from gossip config.
29	    pub(crate) fn gossip(config: &Config, what: WhatAmI, zid: ZenohIdProto) -> Self {
30	        Self {
31	            zid,
32	            matcher: *unwrap_or_default!(config.scouting().gossip().autoconnect().get(what)),
33	            strategy: *unwrap_or_default!(config
34	                .scouting()
35	                .gossip()
36	                .autoconnect_strategy()
37	                .get(what)),
38	        }
39	    }
40	
41	    /// Builds a disabled `AutoConnect`, with [`is_enabled`](Self::is_enabled) or
42	    /// [`should_autoconnect`](Self::should_autoconnect) always return false.
43	    pub(crate) fn disabled() -> Self {
44	        Self {
45	            zid: ZenohIdProto::default(),
46	            matcher: WhatAmIMatcher::empty(),
47	            strategy: TargetDependentValue::Unique(AutoConnectStrategy::default()),
48	        }
49	    }
50	
51	    /// Returns the autonnection matcher.
52	    pub(crate) fn matcher(&self) -> WhatAmIMatcher {
53	        self.matcher
54	    }
55	
56	    /// Returns if the autoconnection is enabled for at least one mode.
57	    pub(crate) fn is_enabled(&self) -> bool {
58	        !self.matcher.is_empty()
59	    }
60	
61	    /// Returns if the node should autoconnect to the other one according to the chosen strategy.
62	    ///
63	    /// The goal is to avoid both node to attempt connecting to each other, as it would result into
64	    /// a waste of resource.
65	    pub(crate) fn should_autoconnect(&self, to: ZenohIdProto, what: WhatAmI) -> bool {
66	        let strategy = || match self.strategy.get(what).copied().unwrap_or_default() {
67	            AutoConnectStrategy::Always => true,
68	            AutoConnectStrategy::GreaterZid => self.zid > to,
69	        };
70	        self.matcher.matches(what) && strategy()
71	    }
72	}
