277	    fn get_zids(&self, whatami: WhatAmI) -> Box<dyn Iterator<Item = ZenohId> + Send + Sync> {
278	        Box::new(
279	            zenoh_runtime::ZRuntime::Application
280	                .block_in_place(self.manager().get_transports_unicast())
281	                .into_iter()
282	                .filter_map(move |s| {
283	                    s.get_whatami()
284	                        .ok()
285	                        .and_then(|what| (what == whatami).then_some(()))
286	                        .and_then(|_| s.get_zid().map(Into::into).ok())
287	                }),
288	        )
289	    }
