330	    ) -> Box<dyn Iterator<Item = Link> + Send + Sync> {
331	        match transport {
332	            None => self.get_links_all(),
333	            Some(t) if t.is_multicast => self.get_links_transport_multicast(&t.zid),
334	            Some(t) => self.get_links_transport_unicast(&t.zid),
335	        }
