425	
426	        match &self.manager.get_shm_context() {
427	            Some(ctx) => match ctx.shm_provider() {
428	                Some(provider) => match provider.try_get_provider() {
429	                    ProviderInitState::Initializing(recv) => ShmProviderState::Initializing(recv),
430	                    ProviderInitState::Ready(provider) => ShmProviderState::Ready(provider),
431	                    ProviderInitState::Error => ShmProviderState::Error,
432	                },
433	                None => ShmProviderState::Disabled,
434	            },
435	            None => ShmProviderState::Disabled,
436	        }
437	    }
