498	    fn get_transports_unicast_peers(&self) -> Vec<TransportPeer> {
499	        zenoh_runtime::ZRuntime::Net
500	            .block_in_place(self.manager.get_transports_unicast())
501	            .into_iter()
502	            .filter_map(|t| t.get_peer().ok())
503	            .collect::<Vec<_>>()
504	    }
