506	    fn get_transports_multicast_peers(&self) -> Vec<Vec<TransportPeer>> {
507	        zenoh_runtime::ZRuntime::Net
508	            .block_in_place(self.manager.get_transports_multicast())
509	            .into_iter()
510	            .filter_map(|t| t.get_peers().ok())
511	            .collect::<Vec<_>>()
512	    }
513	
514	    fn get_links_all(&self) -> Box<dyn Iterator<Item = Link> + Send + Sync> {
515	        let peer_to_links = |peer: TransportPeer| -> Vec<Link> {
516	            let zid: ZenohId = peer.zid.into();
517	            let is_qos = peer.is_qos;
518	            peer.links
519	                .into_iter()
520	                .map(|ref link| Link::new(zid, link, is_qos))
521	                .collect()
522	        };
523	
524	        let unicast_links = self
525	            .get_transports_unicast_peers()
526	            .into_iter()
527	            .flat_map(peer_to_links);
528	
529	        let multicast_links = self
530	            .get_transports_multicast_peers()
531	            .into_iter()
532	            .flatten()
533	            .flat_map(peer_to_links);
534	
535	        Box::new(unicast_links.chain(multicast_links))
536	    }
537	
538	    fn get_links_transport_unicast(
539	        &self,
540	        zid: &ZenohId,
541	    ) -> Box<dyn Iterator<Item = Link> + Send + Sync> {
542	        let links = self
543	            .get_transports_unicast_peers()
544	            .into_iter()
545	            .find(|peer| &ZenohId::from(peer.zid) == zid)
546	            .map(|peer| {
