698	            .then(|| Arc::new(HLCBuilder::new().with_id(uhlc::ID::from(&zid)).build()));
699	
700	        let mut gateway_builder = GatewayBuilder::new(&config);
701	
702	        if let Some(hlc) = hlc.as_ref().cloned() {
703	            gateway_builder = gateway_builder.hlc(hlc.clone());
704	        }
705	
706	        #[cfg(feature = "stats")]
707	        let gateway_builder = gateway_builder.stats(stats.clone());
708	
709	        #[cfg(test)]
710	        let gateway_builder = if let Some(subregions) = subregions {
711	            gateway_builder.subregions(subregions)
712	        } else {
713	            gateway_builder
714	        };
715	
716	        #[cfg(test)]
717	        let gateway_builder =
718	            gateway_builder.disable_async_tree_computation(disable_async_tree_computation);
719	
720	        let gateway = Arc::new(gateway_builder.build()?);
721	
722	        let handler = Arc::new(RuntimeTransportEventHandler {
723	            runtime: std::sync::RwLock::new(WeakRuntime { state: Weak::new() }),
724	        });
725	
726	        let transport_manager_builder = TransportManager::builder()
727	            .from_config(&config)
728	            .await?
729	            .whatami(whatami)
730	            .bound_callback({
731	                let config = config.clone();
732	                move |p| region::compute_transient_bound_of(&p, &config)
733	            });
734	
735	        #[cfg(feature = "shared-memory")]
736	        let transport_manager_builder =
737	            transport_manager_builder.shm_reader(shm_clients.map(ShmReader::new));
738	
739	        let transport_manager = transport_manager_builder.build(
740	            handler.clone(),
741	            #[cfg(feature = "stats")]
742	            stats.clone(),
743	        )?;
744	
745	        // Plugins manager
746	        #[cfg(feature = "plugins")]
747	        let plugins_manager = plugins_manager
748	            .take()
749	            .unwrap_or_else(|| load_plugins(&config));
750	        // Admin space creation flag
751	        let start_admin_space = *config.adminspace.enabled();
752	        // SHM lazy init flag
753	        #[cfg(feature = "shared-memory")]
754	        let shm_init_mode = *config.transport.shared_memory.mode();
755	
756	        let namespace = config.namespace().clone();
757	        let config = Notifier::new(config);
758	        let span = tracing::debug_span!("rt", zid = %zid.short());
759	        let runtime = Runtime {
760	            state: Arc::new(RuntimeState {
761	                zid: zid.into(),
762	                whatami,
763	                next_id: AtomicU32::new(1), // 0 is reserved for routing core
764	                router: gateway,
765	                config,
766	                manager: transport_manager,
767	                transport_handlers: std::sync::RwLock::new(vec![]),
768	                locators: std::sync::RwLock::new(vec![]),
769	                hlc,
770	                task_controller: TaskController::default(),
771	                #[cfg(feature = "plugins")]
772	                plugins_manager: Mutex::new(plugins_manager),
773	                start_conditions: Arc::new(StartConditions::default()),
774	                pending_connections: tokio::sync::Mutex::new(HashSet::new()),
775	                namespace,
776	                #[cfg(feature = "stats")]
777	                stats,
778	                span,
779	            }),
780	        };
781	        *handler.runtime.write().unwrap() = Runtime::downgrade(&runtime);
782	        get_mut_unchecked(&mut runtime.state.router.clone()).init_hats(runtime.clone())?;
783	
784	        // Admin space
785	        if start_admin_space {
786	            AdminSpace::start(&runtime).await;
787	        }
788	
789	        // Start plugins
790	        #[cfg(feature = "plugins")]
791	        start_plugins(&runtime);
792	
793	        #[cfg(feature = "shared-memory")]
794	        match shm_init_mode {
795	            zenoh_config::ShmInitMode::Init => zenoh_shm::init::init(),
796	            zenoh_config::ShmInitMode::Lazy => {}
797	        };
798	
799	        Ok(runtime)
800	    }
