130	impl AdminSpace {
131	    #[cfg(all(feature = "plugins", feature = "runtime_plugins"))]
132	    fn start_plugin(
133	        plugin_mgr: &mut PluginsManager,
134	        config: &zenoh_config::PluginLoad,
135	        start_args: &DynamicRuntime,
136	        required: bool,
137	    ) -> ZResult<()> {
138	        let id = &config.id;
139	        let name = &config.name;
140	        let declared = if let Some(declared) = plugin_mgr.plugin_mut(id) {
141	            tracing::warn!("Plugin `{}` was already declared", declared.id());
142	            declared
143	        } else if let Some(paths) = &config.paths {
144	            plugin_mgr.declare_dynamic_plugin_by_paths(id, name, paths, required)?
145	        } else {
146	            plugin_mgr.declare_dynamic_plugin_by_name(id, name, required)?
147	        };
148	
149	        let loaded = if let Some(loaded) = declared.loaded_mut() {
150	            tracing::warn!(
151	                "Plugin `{}` was already loaded from {}",
152	                loaded.id(),
153	                loaded.path()
154	            );
155	            loaded
156	        } else {
157	            match declared.load()? {
158	                Some(loaded) => loaded,
159	                None => {
160	                    tracing::warn!(
161	                        "Plugin `{}` will not be loaded as plugin loading is disabled",
162	                        config.name
163	                    );
164	                    return Ok(());
165	                }
166	            }
167	        };
168	
169	        if let Some(started) = loaded.started_mut() {
170	            tracing::warn!("Plugin `{}` was already started", started.id());
171	        } else {
172	            let started = loaded.start(start_args)?;
173	            tracing::info!(
174	                "Successfully started plugin `{}` from {}",
175	                started.id(),
176	                started.path()
177	            );
178	        };
179	
180	        Ok(())
181	    }
182	
183	    pub async fn start(runtime: &Runtime) {
184	        let zid_str = runtime.state.zid.to_string();
185	        let whatami_str = runtime.state.whatami.to_str();
186	        let config = &mut runtime.config().lock();
187	        let root_key: OwnedKeyExpr = format!("@/{zid_str}/{whatami_str}").try_into().unwrap();
188	
189	        let mut handlers: HashMap<OwnedKeyExpr, (Handler, OwnedKeyExpr)> = HashMap::new();
190	        macro_rules! add_handler {
191	            ($key:expr, $glob:expr, $handler:expr) => {{
192	                let key_expr = keyexpr::new($key).unwrap();
193	                let glob_expr = keyexpr::new($glob).unwrap();
194	                let prefix = &root_key / key_expr;
195	                let full_key = &prefix / glob_expr;
196	                handlers.insert(full_key, (Arc::new($handler), prefix));
197	            }};
198	            ($key:expr, $handler:expr) => {{
199	                let key_expr = keyexpr::new($key).unwrap();
200	                let full_key = &root_key / key_expr;
201	                handlers.insert(full_key.clone(), (Arc::new($handler), full_key));
202	            }};
203	            ($handler:expr) => {{
204	                handlers.insert(root_key.clone(), (Arc::new($handler), root_key.clone()));
205	            }};
206	        }
207	
208	        add_handler!(local_data);
209	        add_handler!("metrics", metrics);
210	        add_handler!("linkstate", "*", linkstate_data);
211	        add_handler!("subscriber", "**", subscribers_data);
212	        add_handler!("publisher", "**", publishers_data);
213	        add_handler!("queryable", "**", queryables_data);
214	        add_handler!("querier", "**", queriers_data);
215	        add_handler!("token", "**", tokens_data);
216	        add_handler!("route/successor", "**", route_successor);
217	
218	        #[cfg(feature = "plugins")]
219	        add_handler!("plugins", "**", plugins_data);
220	        #[cfg(feature = "plugins")]
221	        add_handler!("status/plugins", "**", plugins_status);
222	
223	        #[cfg(all(feature = "plugins", feature = "runtime_plugins"))]
224	        let mut active_plugins = runtime
225	            .plugins_manager()
226	            .started_plugins_iter()
227	            .map(|rec| (rec.id().to_string(), rec.path().to_string()))
228	            .collect::<HashMap<_, _>>();
229	
230	        let context = Arc::new(AdminContext {
231	            runtime: runtime.clone(),
232	        });
233	        let admin = Arc::new(AdminSpace {
234	            zid: runtime.zid(),
235	            queryable_id: runtime.next_id(),
236	            primitives: Mutex::new(None),
237	            mappings: Mutex::new(HashMap::new()),
238	            handlers,
239	            context,
240	        });
241	
242	        config.set_plugin_validator(Arc::downgrade(&admin));
243	
244	        #[cfg(all(feature = "plugins", feature = "runtime_plugins"))]
245	        {
246	            let cfg_rx = admin.context.runtime.state.config.subscribe();
247	
248	            // REVIEW(regions): this was changed from `tokio::task::spawn` in order to enable
249	            // `plugins` builds to run outside the context of a Tokio executor.
250	            zenoh_runtime::ZRuntime::Net.spawn({
251	                let admin = admin.clone();
252	                async move {
253	                    while let Ok(change) = cfg_rx.recv_async().await {
254	                        let change = change.strip_prefix('/').unwrap_or(&change);
255	                        if !change.starts_with("plugins") {
256	                            continue;
257	                        }
258	
259	                        let requested_plugins = {
260	                            let cfg_guard = admin.context.runtime.state.config.lock();
261	                            cfg_guard.plugins().load_requests().collect::<Vec<_>>()
262	                        };
263	                        let mut diffs = Vec::new();
264	                        for plugin in active_plugins.keys() {
265	                            if !requested_plugins.iter().any(|r| &r.id == plugin) {
266	                                diffs.push(PluginDiff::Delete(plugin.clone()))
267	                            }
268	                        }
269	                        for request in requested_plugins {
270	                            if let Some(active) = active_plugins.get(&request.id) {
271	                                if request
272	                                    .paths
273	                                    .as_ref()
274	                                    .map(|p| p.contains(active))
275	                                    .unwrap_or(true)
276	                                {
277	                                    continue;
278	                                }
279	                                diffs.push(PluginDiff::Delete(request.id.clone()))
280	                            }
281	                            diffs.push(PluginDiff::Start(request))
282	                        }
283	                        let mut plugins_mgr = admin.context.runtime.plugins_manager();
284	                        for diff in diffs {
285	                            match diff {
286	                                PluginDiff::Delete(id) => {
287	                                    active_plugins.remove(id.as_str());
288	                                    if let Some(running) = plugins_mgr.started_plugin_mut(&id) {
289	                                        running.stop()
290	                                    }
291	                                }
292	                                PluginDiff::Start(plugin) => {
293	                                    let dynamic_runtime = admin.context.runtime.clone().into();
294	                                    if let Err(e) = Self::start_plugin(
295	                                        &mut plugins_mgr,
296	                                        &plugin,
297	                                        &dynamic_runtime,
298	                                        plugin.required,
299	                                    ) {
300	                                        if plugin.required {
301	                                            panic!("Failed to load plugin `{}`: {}", plugin.id, e)
302	                                        } else {
303	                                            tracing::error!(
304	                                                "Failed to load plugin `{}`: {}",
305	                                                plugin.id,
306	                                                e
307	                                            )
308	                                        }
309	                                    }
310	                                }
311	                            }
312	                        }
313	                    }
314	                    tracing::info!("Running plugins: {:?}", &active_plugins)
315	                }
316	            });
317	        }
318	
319	        let _span =
320	            tracing::debug_span!("adminspace", zid = %ZenohIdProto::from(admin.zid).short())
321	                .entered();
322	
323	        let primitives = runtime.state.router.new_session(admin.clone());
324	        zlock!(admin.primitives).replace(primitives.clone());
325	
326	        primitives.send_declare(&mut Declare {
327	            interest_id: None,
328	            ext_qos: ext::QoSType::DECLARE,
329	            ext_tstamp: None,
330	            ext_nodeid: ext::NodeIdType::DEFAULT,
331	            body: DeclareBody::DeclareQueryable(DeclareQueryable {
332	                id: runtime.next_id(),
333	                wire_expr: [&root_key, "/**"].concat().into(),
334	                ext_info: QueryableInfoType::DEFAULT,
335	            }),
336	        });
337	
338	        primitives.send_declare(&mut Declare {
339	            interest_id: None,
340	            ext_qos: ext::QoSType::DECLARE,
341	            ext_tstamp: None,
342	            ext_nodeid: ext::NodeIdType::DEFAULT,
343	            body: DeclareBody::DeclareSubscriber(DeclareSubscriber {
344	                id: runtime.next_id(),
345	                wire_expr: [&root_key, "/config/**"].concat().into(),
346	            }),
347	        });
348	    }
