350	    pub fn key_expr_to_string<'a>(&self, key_expr: &'a WireExpr) -> ZResult<KeyExpr<'a>> {
351	        if key_expr.scope == EMPTY_EXPR_ID {
352	            key_expr.suffix.as_ref().try_into()
353	        } else if key_expr.suffix.is_empty() {
354	            match zlock!(self.mappings).get(&key_expr.scope) {
355	                Some(prefix) => prefix.clone().try_into(),
356	                None => bail!("Failed to resolve ExprId {}", key_expr.scope),
357	            }
358	        } else {
359	            match zlock!(self.mappings).get(&key_expr.scope) {
360	                Some(prefix) => format!("{}{}", prefix, key_expr.suffix.as_ref()).try_into(),
361	                None => bail!("Failed to resolve ExprId {}", key_expr.scope),
362	            }
363	        }
364	    }
365	}
