367	impl Primitives for AdminSpace {
368	    fn send_interest(&self, msg: &mut Interest) {
369	        tracing::trace!("Recv interest {:?}", msg);
370	    }
371	
372	    fn send_declare(&self, msg: &mut Declare) {
373	        tracing::trace!("Recv declare {:?}", msg);
374	        if let DeclareBody::DeclareKeyExpr(m) = &msg.body {
375	            match self.key_expr_to_string(&m.wire_expr) {
376	                Ok(s) => {
377	                    zlock!(self.mappings).insert(m.id, s.into());
378	                }
379	                Err(e) => error!("Unknown expr_id {}! ({})", m.id, e),
380	            }
381	        }
382	    }
383	
384	    fn send_push_consume(&self, msg: &mut Push, _reliability: Reliability, _consume: bool) {
385	        trace!("recv Push {:?}", msg);
386	        {
387	            let conf = &self.context.runtime.state.config.lock();
388	            if !conf.adminspace.permissions().write {
389	                tracing::error!(
390	                    "Received PUT on '{}' but adminspace.permissions.write=false in configuration",
391	                    msg.wire_expr
392	                );
393	                return;
394	            }
395	        }
396	
397	        if let Some(key) = msg.wire_expr.as_str().strip_prefix(&format!(
398	            "@/{}/{}/config/",
399	            self.context.runtime.state.zid, self.context.runtime.state.whatami,
400	        )) {
401	            match &msg.payload {
402	                PushBody::Put(put) => match std::str::from_utf8(&put.payload.contiguous()) {
403	                    Ok(json) => {
404	                        tracing::trace!(
405	                            "Insert conf value @/{}/{}/config/{} : {}",
406	                            self.context.runtime.state.zid,
407	                            self.context.runtime.state.whatami,
408	                            key,
409	                            json
410	                        );
411	                        let config = &self.context.runtime.state.config;
412	                        if let Err(e) =
413	                            config
414	                                .try_insert_json5_array_item(key, json)
415	                                .and_then(|applied| {
416	                                    if applied {
417	                                        Ok(())
418	                                    } else {
419	                                        config.insert_json5(key, json)
420	                                    }
421	                                })
422	                        {
423	                            error!(
424	                                "Error inserting conf value @/{}/{}/config/{} : {} - {}",
425	                                self.context.runtime.state.zid,
426	                                self.context.runtime.state.whatami,
427	                                key,
428	                                json,
429	                                e
430	                            );
431	                        }
432	                    }
433	                    Err(e) => error!(
434	                        "Received non utf8 conf value on @/{}/{}/config/{} : {}",
435	                        self.context.runtime.state.zid, self.context.runtime.state.whatami, key, e
436	                    ),
437	                },
438	                PushBody::Del(_) => {
439	                    tracing::trace!(
440	                        "Deleting conf value /@/{}/{}/config/{}",
441	                        self.context.runtime.state.zid,
442	                        self.context.runtime.state.whatami,
443	                        key
444	                    );
445	                    let config = &self.context.runtime.state.config;
446	                    if let Err(e) = config.try_remove_json5_array_item(key).and_then(|applied| {
447	                        if applied {
448	                            Ok(())
449	                        } else {
450	                            config.remove(key)
451	                        }
452	                    }) {
453	                        tracing::error!("Error deleting conf value {} : {}", msg.wire_expr, e)
454	                    }
455	                }
456	            }
457	        }
458	    }
459	
460	    fn send_request(&self, msg: &mut Request) {
461	        trace!("recv Request {:?}", msg);
462	        match &mut msg.payload {
463	            RequestBody::Query(query) => {
464	                let _span =
465	                    tracing::debug_span!("adminspace", zid = %ZenohIdProto::from(self.zid).short())
466	                        .entered();
467	                let primitives = zlock!(self.primitives).as_ref().unwrap().clone();
468	                {
469	                    let conf = &self.context.runtime.state.config.lock();
470	                    if !conf.adminspace.permissions().read {
471	                        tracing::error!(
472	                        "Received GET on '{}' but adminspace.permissions.read=false in configuration",
473	                        msg.wire_expr
474	                    );
475	                        primitives.send_response_final(&mut ResponseFinal {
476	                            rid: msg.id,
477	                            ext_qos: msg.ext_qos,
478	                            ext_tstamp: None,
479	                        });
480	                        return;
481	                    }
482	                }
483	
484	                let key_expr = match self.key_expr_to_string(&msg.wire_expr) {
485	                    Ok(key_expr) => key_expr.into_owned(),
486	                    Err(e) => {
487	                        tracing::error!("Unknown KeyExpr: {}", e);
488	                        primitives.send_response_final(&mut ResponseFinal {
489	                            rid: msg.id,
490	                            ext_qos: msg.ext_qos,
491	                            ext_tstamp: None,
492	                        });
493	                        return;
494	                    }
495	                };
496	                let zid = self.zid;
497	                let query = Query {
498	                    inner: Arc::new(QueryInner {
499	                        key_expr: key_expr.clone(),
500	                        parameters: mem::take(&mut query.parameters).into(),
501	                        qid: msg.id,
502	                        zid: zid.into(),
503	                        qos: msg.ext_qos.into(),
504	                        #[cfg(feature = "unstable")]
505	                        source_info: query.ext_sinfo.map(Into::into),
506	                        primitives: ReplyPrimitives::new_remote(None, primitives),
507	                    }),
508	                    eid: self.queryable_id,
509	                    value: mem::take(&mut query.ext_body)
510	                        .map(|b| (b.payload.into(), b.encoding.into())),
511	                    attachment: query.ext_attachment.take().map(Into::into),
512	                };
513	
514	                for (full_key, (handler, prefix)) in &self.handlers {
515	                    if key_expr.intersects(full_key) {
516	                        handler(prefix, &self.context, query.clone());
517	                    }
518	                }
519	            }
