583	fn local_data(prefix: &keyexpr, context: &AdminContext, query: Query) {
584	    let transport_mgr = context.runtime.manager().clone();
585	
586	    // plugins info
587	    #[cfg(feature = "plugins")]
588	    let plugins: serde_json::Value = {
589	        let plugins_mgr = context.runtime.plugins_manager();
590	        plugins_mgr
591	            .started_plugins_iter()
592	            .map(|rec| (rec.id(), json!({"name":rec.name(), "path": rec.path() })))
593	            .collect()
594	    };
595	    #[cfg(not(all(feature = "unstable", feature = "plugins")))]
596	    let plugins = serde_json::Value::Null;
597	
598	    // locators info
599	    let locators: Vec<serde_json::Value> = transport_mgr
600	        .get_locators()
601	        .iter()
602	        .map(|locator| json!(locator.as_str()))
603	        .collect();
604	
605	    let links_info = context.runtime.get_links_info();
606	
607	    let config = context.runtime.config().lock().clone();
608	    // FIXME(regions): this should not be re-computed (and the config need not be cloned).
609	    let transport_unicast_to_region = move |transport: &TransportUnicast| -> Option<Region> {
610	        let peer = transport.get_peer().ok()?;
611	        let transient_remote_bound = transport.get_bound().ok()?;
612	        let (region, _) =
613	            region::compute_region_of(&peer, &config, transient_remote_bound.as_ref()).ok()?;
614	        Some(region)
615	    };
616	    // transports info
617	    let transport_unicast_to_json = move |transport: &TransportUnicast| {
618	        let link_to_json = |link: &Link| {
619	            json!({
620	                "src": link.src.to_string(),
621	                "dst": link.dst.to_string()
622	            })
623	        };
624	        let links = transport
625	            .get_links()
626	            .unwrap_or_default()
627	            .iter()
628	            .map(link_to_json)
629	            .collect_vec();
630	        #[cfg(feature = "shared-memory")]
631	        let shm = transport.is_shm().unwrap_or_default();
632	        #[cfg(not(feature = "shared-memory"))]
633	        let shm = false;
634	        let json = json!({
635	            "peer": transport.get_zid().map_or_else(|_| "unknown".to_string(), |p| p.to_string()),
636	            "whatami": transport.get_whatami().map_or_else(|_| "unknown".to_string(), |p| p.to_string()),
637	            "links": links,
638	            "weight": transport.get_zid().ok().and_then(|zid| links_info.get(&zid)),
639	            "shm": shm,
640	            "region": transport_unicast_to_region(transport).map_or_else(|| "unknown".to_string(), |r| r.to_string())
641	        });
642	        json
643	    };
644	    let transport_multicast_peer_to_json =
645	        |transport: &TransportMulticast, mcast_peer: &TransportPeer| {
646	            let link_to_json = |link: &Link| {
647	                json!({
648	                    "src": link.src.to_string(),
649	                    "dst": link.dst.to_string()
650	                })
651	            };
652	            let links = mcast_peer.links.iter().map(link_to_json).collect_vec();
653	            let json = json!({
654	                "peer": mcast_peer.zid.to_string(),
655	                "whatami": mcast_peer.whatami.to_string(),
656	                "group": transport
657	                    .get_link()
658	                    .ok()
659	                    .and_then(|t| t.group.map(|g| g.to_string()))
660	                    .unwrap_or("unknown".to_string()),
661	
662	                "links": links,
663	            });
664	            json
665	        };
666	    let mut transports: Vec<serde_json::Value> = vec![];
667	    zenoh_runtime::ZRuntime::Net.block_in_place(async {
668	        for transport in transport_mgr.get_transports_unicast().await {
669	            transports.push(transport_unicast_to_json(&transport));
670	        }
671	        for mcast_transport in transport_mgr.get_transports_multicast().await {
672	            if let Ok(peers) = mcast_transport.get_peers() {
673	                for mcast_peer in &peers {
674	                    transports.push(transport_multicast_peer_to_json(
675	                        &mcast_transport,
676	                        mcast_peer,
677	                    ));
678	                }
679	            }
680	        }
681	    });
682	    #[cfg_attr(not(feature = "stats"), allow(unused_mut))]
683	    let mut json = json!({
684	        "zid": context.runtime.state.zid,
685	        "version": &*LONG_VERSION,
686	        "metadata": context.runtime.config().lock().metadata(),
687	        "locators": locators,
688	        "sessions": transports,
689	        "plugins": plugins,
690	    });
691	
692	    #[cfg(feature = "stats")]
693	    if query
694	        .parameters()
695	        .iter()
696	        .any(|(k, v)| k == "_stats" && v != "false")
697	    {
698	        context.runtime.stats().merge_stats(&mut json);
699	    }
700	
701	    tracing::trace!("AdminSpace router_data: {:?}", json);
702	    let payload = match serde_json::to_vec(&json) {
703	        Ok(bytes) => ZBytes::from(bytes),
704	        Err(e) => {
705	            tracing::error!("Error serializing AdminSpace reply: {:?}", e);
706	            return;
707	        }
708	    };
709	    if let Err(e) = query
710	        .reply(prefix, payload)
711	        .encoding(Encoding::APPLICATION_JSON)
712	        .wait()
713	    {
714	        tracing::error!("Error sending AdminSpace reply: {:?}", e);
715	    }
716	}
