719	fn metrics(prefix: &keyexpr, context: &AdminContext, query: Query) {
720	    #[cfg(not(feature = "stats"))]
721	    let mut metrics = format!(
722	        concat!(
723	            "# HELP zenoh_build Zenoh build version.\n",
724	            "# TYPE zenoh_build info\n",
725	            "zenoh_build_info{{local_id=\"{zid}\",local_whatami=\"{whatami}\",version=\"{version}\"}} 1\n",
726	            "# EOF\n ",
727	        ),
728	        zid = context.runtime.state.zid,
729	        whatami = context.runtime.state.whatami,
730	        version = &*LONG_VERSION,
731	    );
732	    #[cfg(feature = "stats")]
733	    let mut metrics = String::new();
734	    #[cfg(feature = "stats")]
735	    context
736	        .runtime
737	        .stats()
738	        .encode_metrics(
739	            &mut metrics,
740	            query.parameters().get("per_transport") != Some("false"),
741	            query.parameters().get("per_link") != Some("false"),
742	            query.parameters().get("disconnected") == Some("true"),
743	            query.parameters().get("per_key") != Some("false"),
744	        )
745	        .expect("metrics should be encodable");
746	    if query.parameters().get("descriptors") == Some("false") {
747	        metrics = metrics
748	            .split_inclusive("\n")
749	            .filter(|l| !l.starts_with('#'))
750	            .chain(["# EOF\n"])
751	            .collect();
752	    }
753	    let mut metrics = metrics.into_bytes();
754	    let mut encoding = METRICS_ENCODING.to_string();
755	    if query.parameters().get("compression") != Some("false") {
756	        let mut encoder = flate2::write::GzEncoder::new(Vec::new(), flate2::Compression::fast());
757	        encoder.write_all(&metrics).unwrap();
758	        metrics = encoder.finish().unwrap();
759	        encoding.push_str(";content-encoding=gzip");
760	    }
761	    if let Err(e) = query.reply(prefix, metrics).encoding(encoding).wait() {
762	        tracing::error!("Error sending AdminSpace reply: {:?}", e);
763	    }
764	}
