766	fn resources_data<F>(prefix: &keyexpr, context: &AdminContext, query: Query, f: F)
767	where
768	    F: Fn(&Tables) -> HashMap<Arc<Resource>, Sources>,
769	{
770	    let tables = &context.runtime.state.router.tables;
771	    let rtables = zread!(tables.tables);
772	    for res in f(&rtables) {
773	        let key = prefix / keyexpr::new(res.0.expr()).unwrap();
774	        if query.key_expr().intersects(&key) {
775	            let payload =
776	                ZBytes::from(serde_json::to_string(&res.1).unwrap_or_else(|_| "{}".to_string()));
777	            if let Err(e) = query
778	                .reply(key, payload)
779	                .encoding(Encoding::APPLICATION_JSON)
780	                .wait()
781	            {
782	                tracing::error!("Error sending AdminSpace reply: {:?}", e);
783	            }
784	        }
785	    }
786	}
