839	#[tracing::instrument(level = "trace", skip_all)]
840	fn route_successor(prefix: &keyexpr, context: &AdminContext, query: Query) {
841	    let reply = |ke: &keyexpr, successor: ZenohIdProto| {
842	        if let Err(e) = query
843	            .reply(ke, serde_json::to_vec(&json!(successor)).unwrap())
844	            .encoding(Encoding::APPLICATION_JSON)
845	            .wait()
846	        {
847	            tracing::error!("Error sending AdminSpace reply: {:?}", e);
848	        }
849	    };
850	    let tables = &context.runtime.state.router.tables;
851	    let rtables = zread!(tables.tables);
852	
853	    // Try to shortcut full successor retrieval if suffix matches 'src/<zid>/dst/<zid>' pattern.
854	
855	    let suffix = query.key_expr().as_str().strip_prefix(prefix.as_str());
856	    if let Some((src, dst)) = suffix.and_then(|s| s.strip_prefix("/src/")?.split_once("/dst/")) {
857	        if let (Ok(src_zid), Ok(dst_zid)) = (src.parse(), dst.parse()) {
858	            for hat in rtables.hats.values().filter(|hat| hat.mode().is_router()) {
859	                if let Some(successor) = hat.route_successor(src_zid, dst_zid) {
860	                    reply(query.key_expr(), successor);
861	                }
862	            }
863	        }
864	    }
865	
866	    // Reply with every successor suffix matching the keyexpr.
867	    let successors = rtables
868	        .hats
869	        .values()
870	        .filter(|hat| hat.mode().is_router())
871	        .flat_map(|hat| hat.route_successors())
872	        .collect_vec();
873	    drop(rtables);
874	    for entry in successors {
875	        let ke = KeyExpr::new(format!(
876	            "{prefix}/src/{src}/dst/{dst}",
877	            src = entry.source,
878	            dst = entry.destination
879	        ))
880	        .unwrap();
881	        if query.key_expr().intersects(&ke) {
882	            reply(&ke, entry.successor);
883	        }
884	    }
885	}
