913	#[cfg(feature = "plugins")]
914	fn plugins_status(prefix: &keyexpr, context: &AdminContext, query: Query) {
915	    let key_expr = query.key_expr();
916	    let guard = context.runtime.plugins_manager();
917	    let mut root_key = prefix.as_str().to_string();
918	    for plugin in guard.started_plugins_iter() {
919	        with_extended_string(&mut root_key, &["/", plugin.id()], |plugin_key| {
920	            // @TODO: response to "__version__", this need not to be implemented by each plugin
921	            with_extended_string(plugin_key, &["/__path__"], |plugin_path_key| {
922	                if let Ok(key_expr) = KeyExpr::try_from(plugin_path_key.clone()) {
923	                    if query.key_expr().intersects(&key_expr) {
924	                        if let Err(e) = query
925	                            .reply(key_expr, plugin.path())
926	                            .encoding(Encoding::TEXT_PLAIN)
927	                            .wait()
928	                        {
929	                            tracing::error!("Error sending AdminSpace reply: {:?}", e);
930	                        }
931	                    }
932	                } else {
933	                    tracing::error!("Error: invalid plugin path key {}", plugin_path_key);
934	                }
935	            });
936	            let matches_plugin = |plugin_status_space: &mut String| {
937	                query
938	                    .key_expr()
939	                    .intersects(plugin_status_space.as_str().try_into().unwrap())
940	            };
941	            if !with_extended_string(plugin_key, &["/**"], matches_plugin) {
942	                return;
943	            }
944	            match std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
945	                plugin.instance().adminspace_getter(key_expr, plugin_key)
946	            })) {
947	                Ok(Ok(responses)) => {
948	                    for response in responses {
949	                        if let Ok(key_expr) = KeyExpr::try_from(response.key) {
950	                            match serde_json::to_vec::<serde_json::Value>(&response.value.into()) {
951	                                Ok(bytes) => {
952	                                    if let Err(e) = query.reply(key_expr, bytes).encoding(Encoding::APPLICATION_JSON).wait() {
953	                                        tracing::error!("Error sending AdminSpace reply: {:?}", e);
954	                                    }
955	                                }
956	                                Err(e) => tracing::debug!("Admin query error: {}", e),
957	                            }
958	                        } else {
959	                            tracing::error!("Error: plugin {} replied with an invalid key", plugin_key);
960	                        }
961	                    }
962	                }
963	                Ok(Err(e)) => {
964	                    tracing::error!("Plugin {} bailed from responding to {}: {}", plugin.id(), query.key_expr(), e)
965	                }
966	                Err(e) => match e
967	                    .downcast_ref::<String>()
968	                    .map(|s| s.as_str())
969	                    .or_else(|| e.downcast_ref::<&str>().copied())
970	                {
971	                    Some(e) => tracing::error!("Plugin {} panicked while responding to {}: {}", plugin.id(), query.key_expr(), e),
972	                    None => tracing::error!("Plugin {} panicked while responding to {}. The panic message couldn't be recovered.", plugin.id(), query.key_expr()),
973	                },
974	            }
975	        });
976	    }
977	}
