979	#[cfg(feature = "plugins")]
980	fn with_extended_string<R, F: FnMut(&mut String) -> R>(
981	    prefix: &mut String,
982	    suffixes: &[&str],
983	    mut closure: F,
984	) -> R {
985	    let prefix_len = prefix.len();
986	    for suffix in suffixes {
987	        prefix.push_str(suffix);
988	    }
989	    let result = closure(prefix);
990	    prefix.truncate(prefix_len);
991	    result
992	}
