24	/// Computes the _transient_ [`Bound`] of a remote.
25	///
26	/// This method is used during the Open phase of establishment to decide whether a remote is
27	/// south-bound using the [`zenoh_protocol::transport::open::ext::RemoteBound`] extension.
28	#[tracing::instrument(level = "debug", skip(peer, config), fields(peer.zid = %peer.zid.short(), peer.mode = %peer.whatami), ret)]
29	pub(crate) fn compute_transient_bound_of(
30	    peer: &TransportPeer,
31	    config: &ExpandedConfig,
32	) -> ZResult<Option<Bound>> {
33	    Ok(compute_transient_region_of(peer, config)?.map(|r| r.bound()))
34	}
35	
36	/// Computes the [`Region`] and _remote_ [`Bound`] of a remote.
37	#[tracing::instrument(level = "debug", skip(peer, config), fields(peer.zid = %peer.zid.short(), peer.mode = %peer.whatami), ret)]
38	pub(crate) fn compute_region_of(
39	    peer: &TransportPeer,
40	    config: &ExpandedConfig,
41	    transient_remote_bound: Option<&Bound>,
42	) -> ZResult<(Region, Bound)> {
43	    let mode = config.mode();
44	    let remote_mode = peer.whatami;
45	    let transient_region = compute_transient_region_of(peer, config)?;
46	
47	    match (transient_region.map(|r| r.bound()), transient_remote_bound) {
48	        (None, None) => compute_auto_region(mode, remote_mode),
49	        (None, Some(Bound::South)) => Ok((Region::North, Bound::South)),
50	        (Some(Bound::South), None) => Ok((transient_region.unwrap(), Bound::North)),
51	        (None, Some(Bound::North)) => {
52	            let (auto_region, auto_remote_bound) = compute_auto_region(mode, remote_mode)?;
53	
54	            // NOTE(regions): in this case, I am not configured to be a gateway, nor does the auto
55	            // mode allow me to put the remote in the north region. We _could_ in the future adjust
56	            // this to put the remote in a subregion.
57	            if !auto_remote_bound.is_north() {
58	                bail!("Remote's custom configuration conflicts with auto preset")
59	            } else {
60	                Ok((auto_region, Bound::North))
61	            }
62	        }
63	        (Some(Bound::North), None) => {
64	            let (auto_region, auto_remote_bound) = compute_auto_region(mode, remote_mode)?;
65	
66	            // NOTE(regions): see above comment for the symmetric case.
67	            if auto_region.bound().is_south() {
68	                bail!("Remote's auto preset conflicts with custom configuration")
69	            } else {
70	                Ok((Region::North, auto_remote_bound))
71	            }
72	        }
73	        (Some(Bound::North), Some(Bound::North)) => {
74	            if mode != remote_mode {
75	                bail!("North-north {mode}-{remote_mode} configuration (invalid)")
76	            } else {
77	                Ok((Region::North, Bound::North))
78	            }
79	        }
80	        (Some(Bound::South), Some(Bound::South)) => {
81	            bail!("South-south configuration (invalid)")
82	        }
83	        (Some(Bound::North), Some(Bound::South)) | (Some(Bound::South), Some(Bound::North)) => {
84	            Ok((transient_region.unwrap(), *transient_remote_bound.unwrap()))
85	        }
86	    }
87	}
