92	/// Computes the [`Region`] of a multicast transport.
93	#[tracing::instrument(level = "debug", skip(config), ret)]
94	pub(crate) fn compute_multicast_region(config: &ExpandedConfig) -> ZResult<Region> {
95	    match config.mode() {
96	        WhatAmI::Peer => Ok(Region::North),
97	        WhatAmI::Router => Ok(Region::default_south(WhatAmI::Peer)),
98	        WhatAmI::Client => bail!("{MULTICAST_LIMITATION_NOTICE}"),
99	    }
100	}
101	
102	/// Computes the [`Region`] and _remote_ [`Bound`] of a multicast remote.
103	#[tracing::instrument(level = "debug", skip(config), ret)]
104	pub(crate) fn compute_multicast_region_of(
105	    peer: &TransportPeer,
106	    config: &ExpandedConfig,
107	) -> ZResult<(Region, Bound)> {
108	    match (config.mode(), peer.whatami) {
109	        (WhatAmI::Peer, WhatAmI::Peer) => Ok((Region::North, Bound::North)),
110	        (WhatAmI::Router, WhatAmI::Peer) => {
111	            Ok((Region::default_south(WhatAmI::Peer), Bound::North))
112	        }
113	        (WhatAmI::Peer, WhatAmI::Router) => Ok((Region::North, Bound::South)),
114	        _ => bail!("{MULTICAST_LIMITATION_NOTICE}"),
115	    }
116	}
117	
118	fn compute_transient_region_of(
119	    peer: &TransportPeer,
120	    config: &ExpandedConfig,
121	) -> ZResult<Option<Region>> {
122	    match config.gateway.south.clone().unwrap_or_default() {
123	        GatewaySouthConf::Preset(GatewayPresetConf::Auto) => Ok(None),
124	        GatewaySouthConf::Custom(subregions) => {
125	            if let Some(id) = subregions
126	                .iter()
127	                .position(|s| is_match(s.filters.as_deref(), peer))
128	            {
129	                if peer.whatami.is_router() && !config.mode().is_router() {
130	                    bail!("Router regions cannot be subregions of non-router regions (unsupported)")
131	                }
132	
133	                Ok(Some(Region::South {
134	                    id,
135	                    mode: peer.whatami,
136	                }))
137	            } else {
138	                Ok(Some(Region::North))
139	            }
140	        }
141	    }
142	}
143	
144	/// Computes the _auto_ [`Region`] and _remote_ [`Bound`] of a remote.
145	fn compute_auto_region(mode: WhatAmI, remote_mode: WhatAmI) -> ZResult<(Region, Bound)> {
146	    match (mode, remote_mode) {
147	        (WhatAmI::Router, WhatAmI::Peer | WhatAmI::Client) | (WhatAmI::Peer, WhatAmI::Client) => {
148	            Ok((Region::default_south(remote_mode), Bound::North))
149	        }
150	        (WhatAmI::Router, WhatAmI::Router) | (WhatAmI::Peer, WhatAmI::Peer) => {
151	            Ok((Region::North, Bound::North))
152	        }
153	        (WhatAmI::Peer | WhatAmI::Client, WhatAmI::Router) | (WhatAmI::Client, WhatAmI::Peer) => {
154	            Ok((Region::North, Bound::South))
155	        }
156	        (WhatAmI::Client, WhatAmI::Client) => {
157	            bail!("North-north client-client configuration (invalid)")
158	        }
159	    }
160	}
161	
162	#[allow(clippy::incompatible_msrv)]
163	fn is_match(filter: Option<&[GatewayFiltersConf]>, peer: &TransportPeer) -> bool {
164	    filter.is_none_or(|filters| {
165	        filters.iter().any(|filter| {
166	            let value = filter
167	                .zids
168	                .as_ref()
169	                .is_none_or(|zid| zid.contains(&peer.zid.into()))
170	                && filter.interfaces.as_ref().is_none_or(|ifaces| {
171	                    peer.links
172	                        .iter()
173	                        .flat_map(|link| {
174	                            link.interfaces
175	                                .iter()
176	                                .map(|iface| Interface(iface.to_owned()))
177	                        })
178	                        .all(|iface| ifaces.contains(&iface))
179	                })
180	                && filter
181	                    .modes
182	                    .as_ref()
183	                    .is_none_or(|mode| mode.matches(peer.whatami))
184	                && filter.region_names.as_ref().is_none_or(|region_names| {
185	                    peer.region_name
186	                        .as_ref()
187	                        .is_some_and(|region_name| region_names.iter().any(|n| n == region_name))
188	                });
189	
190	            if filter.negated {
191	                !value
192	            } else {
193	                value
194	            }
195	        })
196	    })
197	}
