219	    async fn start_peer(&self) -> ZResult<()> {
220	        let (listeners, peers, scouting, wait_scouting, listen, autoconnect, addr, ifaces, delay) = {
221	            let guard = &self.state.config.lock();
222	            (
223	                guard.listen().endpoints().peer().unwrap_or(&vec![]).clone(),
224	                guard
225	                    .connect()
226	                    .endpoints()
227	                    .peer()
228	                    .unwrap_or(&vec![])
229	                    .clone(),
230	                unwrap_or_default!(guard.scouting().multicast().enabled()),
231	                unwrap_or_default!(guard.open().return_conditions().connect_scouted()),
232	                *unwrap_or_default!(guard.scouting().multicast().listen().peer()),
233	                AutoConnect::multicast(guard, WhatAmI::Peer, self.zid().into()),
234	                unwrap_or_default!(guard.scouting().multicast().address()),
235	                unwrap_or_default!(guard.scouting().multicast().interface()),
236	                Duration::from_millis(unwrap_or_default!(guard.scouting().delay())),
237	            )
238	        };
239	
240	        self.bind_listeners(&listeners).await?;
241	
242	        self.connect_peers(&peers, false).await?;
243	
244	        if scouting {
245	            self.start_scout(listen, autoconnect, addr, ifaces).await?;
246	        }
247	
248	        if wait_scouting
249	            && (scouting || !peers.is_empty())
250	            && tokio::time::timeout(delay, self.state.start_conditions.notified())
251	                .await
252	                .is_err()
253	            && !peers.is_empty()
254	        {
255	            tracing::warn!("Scouting delay elapsed before start conditions are met.");
256	        }
257	        Ok(())
258	    }
