348	    async fn connect_peers(&self, peers: &[EndPoints], single_link: bool) -> ZResult<()> {
349	        let timeout = self.get_global_connect_timeout();
350	        if timeout.is_zero() {
351	            self.connect_peers_impl(peers, single_link).await
352	        } else {
353	            let res = tokio::time::timeout(timeout, async {
354	                self.connect_peers_impl(peers, single_link).await
355	            })
356	            .await;
357	            match res {
358	                Ok(r) => r,
359	                Err(_) => {
360	                    let e = zerror!("Unable to connect to any of {:?}. Timeout!", peers);
361	                    tracing::warn!("{}", &e);
362	                    Err(e.into())
363	                }
364	            }
365	        }
366	    }
