376	    async fn connect_peers_single_link(&self, peers: &[EndPoints]) -> ZResult<()> {
377	        let mut success_flag = false;
378	        for peer_group in peers {
379	            Self::warn_if_oneof(peer_group);
380	            // try to connect to each peer in the group
381	            let mut peers_to_retry = Vec::new();
382	            for peer in peer_group.as_vec() {
383	                let endpoint = peer.clone();
384	                let retry_config = self.get_connect_retry_config(&endpoint);
385	                if retry_config.timeout().is_zero() || self.get_global_connect_timeout().is_zero() {
386	                    tracing::debug!(
387	                        "Try to connect: {:?}: global timeout: {:?}, retry: {:?}",
388	                        endpoint,
389	                        self.get_global_connect_timeout(),
390	                        retry_config
391	                    );
392	                    // try to connect directly when there is no timeout configuration
393	                    if self.peer_connector(endpoint).await.is_ok() {
394	                        success_flag = true;
395	                    }
396	                } else {
397	                    peers_to_retry.push(endpoint);
398	                }
399	            }
400	            // sequentially try to connect to one of the remaining peers
401	            // respecting connection retry delays
402	            if self
403	                .peers_connector_retry(peers_to_retry, false)
404	                .await
405	                .is_ok()
406	            {
407	                success_flag = true;
408	            }
409	            // any endpoint in the group is available, it's marked as success and break
410	            if success_flag {
411	                break;
412	            }
413	        }
414	
415	        // return error if none of them succeeded
416	        if success_flag {
417	            Ok(())
418	        } else {
419	            let e = zerror!("Unable to connect to any of {:?}! ", peers);
420	            tracing::warn!("{}", &e);
421	            Err(e.into())
422	        }
423	    }
424	
425	    async fn connect_peers_multiply_links(&self, peers: &[EndPoints]) -> ZResult<()> {
426	        for peer_group in peers {
427	            Self::warn_if_oneof(peer_group);
428	            for peer in peer_group.as_vec() {
429	                let endpoint = peer.clone();
430	                let retry_config = self.get_connect_retry_config(&endpoint);
431	                tracing::debug!(
432	                    "Try to connect: {:?}: global timeout: {:?}, retry: {:?}",
433	                    endpoint,
434	                    self.get_global_connect_timeout(),
435	                    retry_config
436	                );
437	                if retry_config.timeout().is_zero() || self.get_global_connect_timeout().is_zero() {
438	                    // try to connect and exit immediately without retry
439	                    if let Err(e) = self.peer_connector(endpoint).await {
440	                        if retry_config.exit_on_failure {
441	                            return Err(e);
442	                        }
443	                    }
444	                } else if retry_config.exit_on_failure {
445	                    // try to connect with retry waiting
446	                    let _ = self.peer_connector_retry(endpoint).await;
447	                } else {
448	                    // try to connect in background
449	                    if let Err(e) = self.spawn_peer_connector(endpoint.clone()).await {
450	                        tracing::warn!("Error connecting to {}: {}", endpoint, e);
451	                        return Err(e);
452	                    }
453	                }
454	            }
455	        }
456	        Ok(())
457	    }
