459	    async fn peer_connector(&self, peer: EndPoint) -> ZResult<()> {
460	        let result = self
461	            .manager()
462	            .open_transport_unicast(peer.clone())
463	            .await
464	            .and_then(|transport| -> ZResult<_> {
465	                let cb = transport
466	                    .get_callback()?
467	                    .ok_or_else(|| zerror!("Transport closed immediately"))?;
468	                let session = cb
469	                    .as_any()
470	                    .downcast_ref::<super::RuntimeSession>()
471	                    .ok_or_else(|| zerror!("Unexpected callback type"))?;
472	                zwrite!(session.endpoints).insert(peer.clone());
473	                Ok(())
474	            });
475	
476	        if let Err(e) = &result {
477	            tracing::warn!("Unable to connect to {}! {}", peer, e);
478	        }
479	        result
480	    }
