525	    async fn bind_listeners_impl(&self, listeners: &[EndPoint]) -> ZResult<()> {
526	        for listener in listeners {
527	            let endpoint = listener.clone();
528	            let retry_config = self.get_listen_retry_config(&endpoint);
529	            tracing::debug!("Try to add listener: {:?}: {:?}", endpoint, retry_config);
530	            if retry_config.timeout().is_zero() || self.get_global_listener_timeout().is_zero() {
531	                // try to add listener and exit immediately without retry
532	                if let Err(e) = self.add_listener(endpoint).await {
533	                    if retry_config.exit_on_failure {
534	                        return Err(e);
535	                    }
536	                };
537	            } else if retry_config.exit_on_failure {
538	                // try to add listener with retry waiting
539	                self.add_listener_retry(endpoint, retry_config).await
540	            } else {
541	                // try to add listener in background
542	                self.spawn_add_listener(endpoint, retry_config).await
543	            }
544	        }
545	        self.print_locators();
546	        Ok(())
547	    }
