629	    pub async fn bind_mcast_port(
630	        sockaddr: &SocketAddr,
631	        ifaces: &[IpAddr],
632	        multicast_ttl: u32,
633	    ) -> ZResult<UdpSocket> {
634	        let socket = match Socket::new(Domain::for_address(*sockaddr), Type::DGRAM, None) {
635	            Ok(socket) => socket,
636	            Err(err) => {
637	                tracing::error!("Unable to create datagram socket: {}", err);
638	                bail!(err => "Unable to create datagram socket");
639	            }
640	        };
641	        if let Err(err) = socket.set_reuse_address(true) {
642	            tracing::error!("Unable to set SO_REUSEADDR option: {}", err);
643	            bail!(err => "Unable to set SO_REUSEADDR option");
644	        }
645	        let addr: IpAddr = {
646	            #[cfg(unix)]
647	            {
648	                sockaddr.ip()
649	            } // See UNIX Network Programmping p.212
650	            #[cfg(windows)]
651	            {
652	                std::net::Ipv4Addr::UNSPECIFIED.into()
653	            }
654	        };
655	        match socket.bind(&SocketAddr::new(addr, sockaddr.port()).into()) {
656	            Ok(()) => tracing::debug!("UDP port bound to {}", sockaddr),
657	            Err(err) => {
658	                tracing::error!("Unable to bind UDP port {}: {}", sockaddr, err);
659	                bail!(err => "Unable to bind UDP port {}", sockaddr);
660	            }
661	        }
662	
663	        match sockaddr.ip() {
664	            IpAddr::V6(addr) => match socket.join_multicast_v6(&addr, 0) {
665	                Ok(()) => {
666	                    tracing::debug!("Joined multicast group {} on interface 0", sockaddr.ip())
667	                }
668	                Err(err) => {
669	                    tracing::error!(
670	                        "Unable to join multicast group {} on interface 0: {}",
671	                        sockaddr.ip(),
672	                        err
673	                    );
674	                    bail!(err =>
675	                        "Unable to join multicast group {} on interface 0",
676	                        sockaddr.ip()
677	                    )
678	                }
679	            },
680	            IpAddr::V4(addr) => {
681	                for iface in ifaces {
682	                    if let IpAddr::V4(iface_addr) = iface {
683	                        match socket.join_multicast_v4(&addr, iface_addr) {
684	                            Ok(()) => tracing::debug!(
685	                                "Joined multicast group {} on interface {}",
686	                                sockaddr.ip(),
687	                                iface_addr,
688	                            ),
689	                            Err(err) => tracing::warn!(
690	                                "Unable to join multicast group {} on interface {}: {}",
691	                                sockaddr.ip(),
692	                                iface_addr,
693	                                err,
694	                            ),
695	                        }
696	                    } else {
697	                        tracing::warn!(
698	                            "Cannot join IpV4 multicast group {} on IpV6 iface {}",
699	                            sockaddr.ip(),
700	                            iface
701	                        );
702	                    }
703	                }
704	            }
705	        }
706	        tracing::info!("Listening scout messages on {}", sockaddr);
707	
708	        // Must set to nonblocking according to the doc of tokio
709	        // https://docs.rs/tokio/latest/tokio/net/struct.UdpSocket.html#notes
710	        socket.set_nonblocking(true)?;
711	        socket.set_multicast_ttl_v4(multicast_ttl)?;
712	
713	        if sockaddr.is_ipv6() && multicast_ttl > 1 {
714	            tracing::warn!("UDP Multicast TTL has been set to a value greater than 1 on a socket bound to an IPv6 address. This might not have the desired effect");
715	        }
716	
717	        // UdpSocket::from_std requires a runtime even though it's a sync function
718	        let udp_socket = zenoh_runtime::ZRuntime::Net
719	            .block_in_place(async { UdpSocket::from_std(socket.into()) })?;
720	        Ok(udp_socket)
721	    }
