723	    pub fn bind_ucast_port(addr: IpAddr, multicast_ttl: u32) -> ZResult<UdpSocket> {
724	        let sockaddr = || SocketAddr::new(addr, 0);
725	        let socket = match Socket::new(Domain::for_address(sockaddr()), Type::DGRAM, None) {
726	            Ok(socket) => socket,
727	            Err(err) => {
728	                tracing::warn!("Unable to create datagram socket: {}", err);
729	                bail!(err=> "Unable to create datagram socket");
730	            }
731	        };
732	        match socket.bind(&sockaddr().into()) {
733	            Ok(()) => {
734	                #[allow(clippy::or_fun_call)]
735	                let local_addr = socket
736	                    .local_addr()
737	                    .unwrap_or(sockaddr().into())
738	                    .as_socket()
739	                    .unwrap_or(sockaddr());
740	                tracing::debug!("UDP port bound to {}", local_addr);
741	            }
742	            Err(err) => {
743	                tracing::warn!("Unable to bind udp port {}:0: {}", addr, err);
744	                bail!(err => "Unable to bind udp port {}:0", addr);
745	            }
746	        }
747	
748	        // Must set to nonblocking according to the doc of tokio
749	        // https://docs.rs/tokio/latest/tokio/net/struct.UdpSocket.html#notes
750	        socket.set_nonblocking(true)?;
751	        socket.set_multicast_ttl_v4(multicast_ttl)?;
752	
753	        // UdpSocket::from_std requires a runtime even though it's a sync function
754	        let udp_socket = zenoh_runtime::ZRuntime::Net
755	            .block_in_place(async { UdpSocket::from_std(socket.into()) })?;
756	        Ok(udp_socket)
757	    }
