759	    async fn spawn_peer_connector(&self, peer: EndPoint) -> ZResult<()> {
760	        if !LocatorInspector::default()
761	            .is_multicast(&peer.to_locator())
762	            .await?
763	        {
764	            let this = self.clone();
765	            let idx = self.state.start_conditions.add_peer_connector().await;
766	            let config_guard = this.config().lock();
767	            let config = &config_guard;
768	            let gossip = unwrap_or_default!(config.scouting().gossip().enabled());
769	            let wait_declares = unwrap_or_default!(config.open().return_conditions().declares());
770	            drop(config_guard);
771	            self.spawn(async move {
772	                if let Ok(zid) = this.peer_connector_retry(peer).await {
773	                    this.state
774	                        .start_conditions
775	                        .set_peer_connector_zid(idx, zid)
776	                        .await;
777	                }
778	                if !gossip && (!wait_declares || this.whatami() != WhatAmI::Peer) {
779	                    this.state
780	                        .start_conditions
781	                        .terminate_peer_connector(idx)
782	                        .await;
783	                }
784	            });
785	            Ok(())
786	        } else {
787	            bail!("Forbidden multicast endpoint in connect list!")
788	        }
789	    }
