1098	    /// Returns `true` if a new Transport instance is established with `zid` or had already been established.
1099	    pub async fn connect_peer(&self, zid: &ZenohIdProto, locators: &[Locator]) -> bool {
1100	        let manager = self.manager();
1101	        if zid != &manager.zid() {
1102	            let has_unicast = manager.get_transport_unicast(zid).await.is_some();
1103	            let has_multicast = {
1104	                let mut hm = manager.get_transport_multicast(zid).await.is_some();
1105	                for t in manager.get_transports_multicast().await {
1106	                    if let Ok(l) = t.get_link() {
1107	                        if let Some(g) = l.group.as_ref() {
1108	                            hm |= locators.iter().any(|l| l == g);
1109	                        }
1110	                    }
1111	                }
1112	                hm
1113	            };
1114	
1115	            if !has_unicast && !has_multicast {
1116	                tracing::debug!("Try to connect to peer {} via any of {:?}", zid, locators);
1117	                self.connect(zid, locators).await
1118	            } else {
1119	                tracing::trace!("Already connected scouted peer: {}", zid);
1120	                true
1121	            }
1122	        } else {
1123	            true
1124	        }
1125	    }
