1127	    async fn connect_first(
1128	        &self,
1129	        sockets: &[UdpSocket],
1130	        what: WhatAmIMatcher,
1131	        addr: &SocketAddr,
1132	        timeout: std::time::Duration,
1133	    ) -> ZResult<()> {
1134	        let scout = async {
1135	            Runtime::scout(sockets, what, addr, move |hello| async move {
1136	                tracing::info!("Found {:?}", hello);
1137	                if !hello.locators.is_empty() {
1138	                    if self.connect(&hello.zid, &hello.locators).await {
1139	                        return Loop::Break;
1140	                    }
1141	                } else {
1142	                    tracing::debug!("Received Hello with no locators: {:?}", hello);
1143	                }
1144	                Loop::Continue
1145	            })
1146	            .await;
1147	            Ok(())
1148	        };
1149	        let timeout = async {
1150	            tokio::time::sleep(timeout).await;
1151	            bail!("timeout")
1152	        };
1153	        tokio::select! {
1154	            res = scout => { res },
1155	            res = timeout => { res }
1156	        }
1157	    }
