1159	    async fn autoconnect_all(
1160	        &self,
1161	        ucast_sockets: &[UdpSocket],
1162	        autoconnect: AutoConnect,
1163	        addr: &SocketAddr,
1164	    ) {
1165	        Runtime::scout(
1166	            ucast_sockets,
1167	            autoconnect.matcher(),
1168	            addr,
1169	            move |hello| async move {
1170	                if hello.locators.is_empty() {
1171	                    tracing::debug!("Received Hello with no locators: {:?}", hello);
1172	                } else if autoconnect.should_autoconnect(hello.zid, hello.whatami) {
1173	                    self.connect_peer(&hello.zid, &hello.locators).await;
1174	                }
1175	                Loop::Continue
1176	            },
1177	        )
1178	        .await
1179	    }
