1181	    async fn responder(&self, mcast_socket: &UdpSocket, ucast_sockets: &[UdpSocket]) {
1182	        fn get_best_match<'a>(addr: &IpAddr, sockets: &'a [UdpSocket]) -> Option<&'a UdpSocket> {
1183	            fn octets(addr: &IpAddr) -> Vec<u8> {
1184	                match addr {
1185	                    IpAddr::V4(addr) => addr.octets().to_vec(),
1186	                    IpAddr::V6(addr) => addr.octets().to_vec(),
1187	                }
1188	            }
1189	            fn matching_octets(addr: &IpAddr, sock: &UdpSocket) -> usize {
1190	                octets(addr)
1191	                    .iter()
1192	                    .zip(octets(&sock.local_addr().unwrap().ip()))
1193	                    .map(|(x, y)| x.cmp(&y))
1194	                    .position(|ord| ord != std::cmp::Ordering::Equal)
1195	                    .unwrap_or_else(|| octets(addr).len())
1196	            }
1197	            sockets
1198	                .iter()
1199	                .filter(|sock| sock.local_addr().is_ok())
1200	                .max_by(|sock1, sock2| {
1201	                    matching_octets(addr, sock1).cmp(&matching_octets(addr, sock2))
1202	                })
1203	        }
1204	
1205	        let mut buf = vec![0; RCV_BUF_SIZE];
1206	        let local_addrs: Vec<SocketAddr> = ucast_sockets
1207	            .iter()
1208	            .filter_map(|sock| sock.local_addr().ok())
1209	            .collect();
1210	        tracing::debug!("Waiting for UDP datagram...");
1211	        loop {
1212	            let (n, peer) = mcast_socket.recv_from(&mut buf).await.unwrap();
1213	            if local_addrs.contains(&peer) {
1214	                tracing::trace!("Ignore UDP datagram from own socket");
1215	                continue;
1216	            }
1217	
1218	            let mut reader = buf.as_slice()[..n].reader();
1219	            let codec = Zenoh080::new();
1220	            let res: Result<ScoutingMessage, DidntRead> = codec.read(&mut reader);
1221	            if let Ok(msg) = res {
1222	                tracing::trace!("Received {:?} from {}", msg.body, peer);
1223	                if let ScoutingBody::Scout(Scout { what, .. }) = &msg.body {
1224	                    if what.matches(self.whatami()) {
1225	                        let mut wbuf = vec![];
1226	                        let mut writer = wbuf.writer();
1227	                        let codec = Zenoh080::new();
1228	
1229	                        let zid = self.manager().zid();
1230	                        let hello: ScoutingMessage = HelloProto {
1231	                            version: zenoh_protocol::VERSION,
1232	                            whatami: self.whatami(),
1233	                            zid,
1234	                            locators: self.get_locators(),
1235	                        }
1236	                        .into();
1237	                        let socket = get_best_match(&peer.ip(), ucast_sockets).unwrap();
1238	                        tracing::trace!(
1239	                            "Send {:?} to {} on interface {}",
1240	                            hello.body,
1241	                            peer,
1242	                            socket
1243	                                .local_addr()
1244	                                .map_or("unknown".to_string(), |addr| addr.ip().to_string())
1245	                        );
1246	                        codec.write(&mut writer, &hello).unwrap();
1247	
1248	                        if let Err(err) = socket.send_to(wbuf.as_slice(), peer).await {
1249	                            tracing::error!("Unable to send {:?} to {}: {}", hello.body, peer, err);
1250	                        }
1251	                    }
1252	                }
1253	            } else {
1254	                tracing::trace!(
1255	                    "Received unexpected UDP datagram from {}: {:?}",
1256	                    peer,
1257	                    &buf.as_slice()[..n]
1258	                );
1259	            }
1260	        }
1261	    }
