1263	    pub(super) fn closed_session(session: &RuntimeSession) {
1264	        if session.runtime.is_closed() {
1265	            return;
1266	        }
1267	
1268	        if zread!(session.endpoints).is_empty() {
1269	            return;
1270	        }
1271	        let endpoints = session
1272	            .runtime
1273	            .state
1274	            .config
1275	            .lock()
1276	            .connect()
1277	            .endpoints()
1278	            .get(session.runtime.state.whatami)
1279	            .unwrap_or(&vec![])
1280	            .clone();
1281	        let mut peers = vec![];
1282	        for peer in endpoints {
1283	            peers.extend(peer.flatten());
1284	        }
1285	
1286	        if session.runtime.whatami() != WhatAmI::Client {
1287	            let endpoints = std::mem::take(zwrite!(session.endpoints).deref_mut());
1288	            peers.retain(|p| endpoints.contains(p));
1289	        }
1290	
1291	        if !peers.is_empty() {
1292	            let runtime = session.runtime.clone();
1293	            session.runtime.spawn(async move {
1294	                runtime
1295	                    .peers_connector_retry(peers, runtime.whatami() == WhatAmI::Client)
1296	                    .await
1297	            });
1298	        }
1299	    }
1300	
1301	    pub(super) fn closed_link(session: &RuntimeSession, endpoint: EndPoint) {
1302	        if session.runtime.whatami() == WhatAmI::Client {
1303	            // Currently Client can have only one link,
1304	            // so we process reconnect in closed_session
1305	            return;
1306	        }
1307	        if session.runtime.is_closed() {
1308	            return;
1309	        }
1310	        let endpoints = session
1311	            .runtime
1312	            .state
1313	            .config
1314	            .lock()
1315	            .connect()
1316	            .endpoints()
1317	            .get(session.runtime.state.whatami)
1318	            .unwrap_or(&vec![])
1319	            .clone();
1320	        let mut peers = vec![];
1321	        for peer in endpoints {
1322	            peers.extend(peer.flatten());
1323	        }
1324	
1325	        if peers.contains(&endpoint) && zwrite!(session.endpoints).remove(&endpoint) {
1326	            let runtime = session.runtime.clone();
1327	            session.runtime.spawn(async move {
1328	                let _ = runtime.peer_connector_retry(endpoint).await;
1329	            });
1330	        }
1331	    }
