1334	    pub(crate) fn update_network(&self) -> ZResult<()> {
1335	        let router = self.router();
1336	        let _ctrl_lock = zlock!(router.tables.ctrl_lock);
1337	        let mut wtables = zwrite!(router.tables.tables);
