264	    pub fn new_transport_unicast(
265	        &self,
266	        transport: TransportUnicast,
267	        region: Region,
268	        remote_bound: Bound,
269	    ) -> ZResult<Arc<DeMux>> {
270	        let ctrl_lock = zlock!(self.tables.ctrl_lock);
271	        let mut wtables = zwrite!(self.tables.tables);
272	        let tables = &mut *wtables;
273	
274	        let whatami = transport.get_whatami()?;
275	        let fid = tables.data.new_face_id();
276	        let zid = transport.get_zid()?;
277	        let this_zid = tables.data.zid;
278	
279	        let ingress = Arc::new(ArcSwapOption::new(InterceptorsChain::empty().into()));
280	        let mux = Arc::new(Mux::new(transport.clone(), InterceptorsChain::empty()));
281	
282	        #[cfg(feature = "stats")]
283	        let stats = transport.get_stats().ok();
284	
285	        let newface = tables
286	            .data
287	            .faces
288	            .entry(fid)
289	            .or_insert_with(|| {
290	                let builder = FaceStateBuilder::new(
291	                    fid,
292	                    zid,
293	                    region,
294	                    remote_bound,
295	                    mux.clone(),
296	                    tables.hats.map_ref(|hat| hat.new_face()),
297	                )
298	                .whatami(whatami)
299	                .ingress_interceptors(ingress.clone());
300	
301	                #[cfg(feature = "stats")]
302	                let builder = {
303	                    if let Some(stats) = stats {
304	                        builder.stats(stats)
305	                    } else {
306	                        builder
307	                    }
308	                };
309	
310	                Arc::new(builder.build())
311	            })
312	            .clone();
313	
314	        newface.set_interceptors_from_factories(
315	            &tables.data.interceptors,
316	            tables.data.next_interceptor_version.load(Ordering::SeqCst),
317	        );
318	        tracing::debug!("New {}", newface);
319	
320	        let mut face = Face {
321	            tables: self.tables.clone(),
322	            state: newface,
323	        };
324	
325	        let _ = mux.face.set(Face::downgrade(&face));
326	
327	        let mut declares = vec![];
328	        let (owner_hat, other_hats) = tables
329	            .hats
330	            .partition_mut(&region)
331	            .expect("computed transport region should have a corresponding hat");
332	        let ctx = DispatcherContext {
333	            tables_lock: &face.tables,
334	            tables: &mut tables.data,
335	            src_face: &mut face.state,
336	            send_declare: &mut |p, m| declares.push((p.clone(), m)),
337	        };
338	        owner_hat.new_transport_unicast_face(
339	            ctx,
340	            &transport,
341	            other_hats.map(|hat| &**hat as &dyn HatTrait),
342	        )?;
343	        drop(wtables);
344	        drop(ctrl_lock);
345	        for (p, m) in declares {
346	            m.with_mut(|m| p.send_declare(m));
347	        }
348	
349	        Ok(Arc::new(DeMux::new(
350	            face,
351	            Some(transport),
352	            ingress,
353	            this_zid,
354	        )))
355	    }
356	
357	    pub fn new_transport_multicast(
358	        &self,
359	        transport: TransportMulticast,
360	        region: Region,
361	    ) -> ZResult<()> {
362	        let _ctrl_lock = zlock!(self.tables.ctrl_lock);
363	        let mut wtables = zwrite!(self.tables.tables);
364	        let tables = &mut *wtables;
365	
366	        let fid = tables.data.new_face_id();
367	        let mux = Arc::new(McastMux::new(transport.clone(), InterceptorsChain::empty()));
368	
369	        #[cfg(feature = "stats")]
370	        let stats = transport.get_stats().ok();
371	
372	        let builder = FaceStateBuilder::new(
373	            fid,
374	            ZenohIdProto::from_str("1").unwrap(),
375	            region,
376	            Bound::default(), // HACK(regions): this is a placeholder
377	            mux.clone(),
378	            tables.hats.map_ref(|hat| hat.new_face()),
379	        )
380	        .multicast_group(transport);
381	
382	        #[cfg(feature = "stats")]
383	        let builder = {
384	            if let Some(stats) = stats {
385	                builder.stats(stats)
386	            } else {
387	                builder
388	            }
389	        };
390	
391	        let face = Arc::new(builder.build());
392	
393	        face.set_interceptors_from_factories(
394	            &tables.data.interceptors,
395	            tables.data.next_interceptor_version.load(Ordering::SeqCst),
396	        );
397	        let _ = mux.face.set(Face {
398	            state: face.clone(),
399	            tables: self.tables.clone(),
400	        });
401	
402	        tables.data.hats[region].mcast_groups.push(face);
403	
404	        tables.hats[region].disable_all_routes(&mut tables.data);
405	
406	        Ok(())
407	    }
408	
409	    pub fn new_peer_multicast(
410	        &self,
411	        transport: TransportMulticast,
412	        peer: TransportPeer,
413	        region: Region,
414	        remote_bound: Bound,
415	    ) -> ZResult<Arc<DeMux>> {
416	        let _ctrl_lock = zlock!(self.tables.ctrl_lock);
417	        let mut wtables = zwrite!(self.tables.tables);
418	        let tables = &mut *wtables;
419	
420	        let fid = tables.data.new_face_id();
421	        let interceptor = Arc::new(ArcSwapOption::new(InterceptorsChain::empty().into()));
422	        let this_zid = tables.data.zid;
423	
424	        #[cfg(feature = "stats")]
425	        let stats = transport.get_stats().ok();
426	
427	        let builder = FaceStateBuilder::new(
428	            fid,
429	            peer.zid,
430	            region,
431	            remote_bound,
432	            Arc::new(DummyPrimitives),
433	            tables.hats.map_ref(|hat| hat.new_face()),
434	        )
435	        .multicast_group(transport)
436	        .ingress_interceptors(interceptor.clone());
437	
438	        #[cfg(feature = "stats")]
439	        let builder = {
440	            if let Some(stats) = stats {
441	                builder.stats(stats)
442	            } else {
443	                builder
444	            }
445	        };
446	
447	        let face = Arc::new(builder.build());
448	
449	        face.set_interceptors_from_factories(
450	            &tables.data.interceptors,
451	            tables.data.next_interceptor_version.load(Ordering::SeqCst),
452	        );
453	
454	        tables.data.hats[region].mcast_faces.push(face.clone());
455	
456	        tables.hats[region].disable_all_routes(&mut tables.data);
457	
458	        Ok(Arc::new(DeMux::new(
459	            Face {
460	                tables: self.tables.clone(),
461	                state: face,
462	            },
463	            None,
464	            interceptor,
465	            this_zid,
466	        )))
467	    }
