45	    pub(crate) fn new(handler: TransportUnicast, interceptor: InterceptorsChain) -> Mux {
46	        Mux {
47	            handler,
48	            face: OnceLock::new(),
49	            interceptor: ArcSwapOption::new(interceptor.into()),
50	        }
51	    }
52	
53	    #[inline(always)]
54	    fn can_schedule(&self, msg: &mut NetworkMessageMut) -> bool {
55	        if !has_interceptor(&self.interceptor) {
56	            return true;
57	        }
58	        match self.interceptor.load().as_ref() {
59	            Some(interceptor) => interceptor.intercept(
60	                msg,
61	                &mut MuxContext {
62	                    mux: self,
63	                    cache: OnceCell::new(),
64	                    expr: OnceCell::new(),
65	                },
66	            ),
67	            None => true,
68	        }
69	    }
70	
71	    #[inline(always)]
72	    fn schedule(&self, mut msg: NetworkMessageMut) -> bool {
73	        self.can_schedule(&mut msg) && self.handler.schedule(msg).unwrap_or(false)
74	    }
75	}
