77	struct MuxContext<'a> {
78	    mux: &'a Mux,
79	    cache: OnceCell<InterceptorCacheValueType>,
80	    expr: OnceCell<String>,
81	}
82	
83	impl MuxContext<'_> {
84	    fn prefix(&self, msg: &NetworkMessageMut) -> Option<Arc<Resource>> {
85	        if let Some(wire_expr) = msg.wire_expr() {
86	            let wire_expr = wire_expr.to_owned();
87	            if let Some(face) = self.mux.face.get().and_then(|f| f.upgrade()) {
88	                let rtables = zread!(face.tables.tables);
89	                if let Some(prefix) = rtables
90	                    .data
91	                    .get_sent_mapping(&face.state, &wire_expr.scope, wire_expr.mapping)
92	                    .cloned()
93	                {
94	                    return Some(prefix);
95	                }
96	            }
97	        }
98	        None
99	    }
100	}
101	
102	impl InterceptorContext for MuxContext<'_> {
103	    fn face(&self) -> Option<Face> {
104	        self.mux.face.get().and_then(|f| f.upgrade())
105	    }
106	
107	    fn full_expr(&self, msg: &NetworkMessageMut) -> Option<&str> {
108	        if self.expr.get().is_none() {
109	            if let Some(wire_expr) = msg.wire_expr() {
110	                if let Some(prefix) = self.prefix(msg) {
111	                    self.expr
112	                        .set(prefix.expr().to_string() + wire_expr.suffix.as_ref())
113	                        .ok();
114	                }
115	            }
116	        }
117	        self.expr.get().map(|x| x.as_str())
118	    }
119	    fn get_cache(&self, msg: &NetworkMessageMut) -> Option<&Box<dyn Any + Send + Sync>> {
120	        if self.cache.get().is_none() && msg.wire_expr().is_some_and(|we| !we.has_suffix()) {
121	            if let Some(prefix) = self.prefix(msg) {
122	                if let Some(face) = self.mux.face.get().and_then(|f| f.upgrade()) {
123	                    // TODO interceptor can change between the initial load and the cache load
124	                    if let Some(cache) = self
125	                        .mux
126	                        .interceptor
127	                        .load()
128	                        .as_ref()
129	                        .and_then(|i| prefix.get_egress_cache(&face, i))
130	                    {
131	                        self.cache.set(cache).ok();
132	                    }
133	                }
134	            }
135	        }
136	        self.cache.get().and_then(|c| c.get_ref().as_ref())
137	    }
138	}
