140	impl EPrimitives for Mux {
141	    fn send_interest(&self, ctx: RoutingContext<&mut Interest>) -> bool {
142	        let interest_id = ctx.msg.id;
143	
144	        let mut msg = NetworkMessageMut {
145	            body: NetworkBodyMut::Interest(ctx.msg),
146	            reliability: Reliability::Reliable,
147	        };
148	        let mut ctx = RoutingContext {
149	            msg: (),
150	            full_expr: ctx.full_expr,
151	        };
152	
153	        if self.interceptor.load().intercept(&mut msg, &mut ctx) {
154	            self.handler.schedule(msg).unwrap_or(false)
155	        } else {
156	            // send declare final to avoid timeout on blocked interest
157	            if let Some(face) = self.face.get().and_then(|f| f.upgrade()) {
158	                face.reject_interest(interest_id);
159	            }
160	            false
161	        }
162	    }
163	
164	    fn send_declare(&self, ctx: RoutingContext<&mut Declare>) -> bool {
165	        let mut msg = NetworkMessageMut {
166	            body: NetworkBodyMut::Declare(ctx.msg),
167	            reliability: Reliability::Reliable,
168	        };
169	        let mut ctx = RoutingContext {
170	            msg: (),
171	            full_expr: ctx.full_expr,
172	        };
173	
174	        self.interceptor.load().intercept(&mut msg, &mut ctx)
175	            && self.handler.schedule(msg).unwrap_or(false)
176	    }
177	
178	    fn send_push(&self, msg: &mut Push, reliability: Reliability) -> bool {
179	        let msg = NetworkMessageMut {
180	            body: NetworkBodyMut::Push(msg),
181	            reliability,
182	        };
183	        self.schedule(msg)
184	    }
185	
186	    fn send_request(&self, msg: &mut Request) -> bool {
187	        let qos = msg.ext_qos;
188	        let request_id = msg.id;
189	        let mut msg = NetworkMessageMut {
190	            body: NetworkBodyMut::Request(msg),
191	            reliability: Reliability::Reliable,
192	        };
193	        if self.can_schedule(&mut msg) {
194	            self.handler.schedule(msg).unwrap_or(false)
195	        } else {
196	            match self.face.get().and_then(|f| f.upgrade()) {
197	                Some(face) => face.send_response_final(&mut ResponseFinal {
198	                    rid: request_id,
199	                    ext_qos: qos,
200	                    ext_tstamp: None,
201	                }),
202	                None => tracing::error!("Uninitialized multiplexer!"),
203	            }
204	            false
205	        }
206	    }
207	
208	    fn send_response(&self, msg: &mut Response) -> bool {
209	        let msg = NetworkMessageMut {
210	            body: NetworkBodyMut::Response(msg),
211	            reliability: Reliability::Reliable,
212	        };
213	        self.schedule(msg)
214	    }
215	
216	    fn send_response_final(&self, msg: &mut ResponseFinal) -> bool {
217	        let msg = NetworkMessageMut {
218	            body: NetworkBodyMut::ResponseFinal(msg),
219	            reliability: Reliability::Reliable,
220	        };
221	        self.schedule(msg)
222	    }
223	
224	    fn as_any(&self) -> &dyn std::any::Any {
225	        self
226	    }
227	}
