60	struct DeMuxContext<'a> {
61	    demux: &'a DeMux,
62	    cache: OnceCell<InterceptorCacheValueType>,
63	    expr: OnceCell<String>,
64	}
65	
66	impl DeMuxContext<'_> {
67	    fn prefix(&self, msg: &NetworkMessageMut) -> Option<Arc<Resource>> {
68	        if let Some(wire_expr) = msg.wire_expr() {
69	            let wire_expr = wire_expr.to_owned();
70	            let rtables = zread!(self.demux.face.tables.tables);
71	            if let Some(prefix) = rtables
72	                .data
73	                .get_mapping(&self.demux.face.state, &wire_expr.scope, wire_expr.mapping)
74	                .cloned()
75	            {
76	                return Some(prefix);
77	            }
78	        }
79	        None
80	    }
81	}
82	
83	impl InterceptorContext for DeMuxContext<'_> {
84	    fn face(&self) -> Option<Face> {
85	        Some(self.demux.face.clone())
86	    }
87	
88	    fn full_expr(&self, msg: &NetworkMessageMut) -> Option<&str> {
89	        if self.expr.get().is_none() {
90	            if let Some(wire_expr) = msg.wire_expr() {
91	                if let Some(prefix) = self.prefix(msg) {
92	                    self.expr
93	                        .set(prefix.expr().to_string() + wire_expr.suffix.as_ref())
94	                        .ok();
95	                }
96	            }
97	        }
98	        self.expr.get().map(|x| x.as_str())
99	    }
100	    fn get_cache(&self, msg: &NetworkMessageMut) -> Option<&Box<dyn Any + Send + Sync>> {
101	        if self.cache.get().is_none() && msg.wire_expr().is_some_and(|we| !we.has_suffix()) {
102	            if let Some(prefix) = self.prefix(msg) {
103	                // TODO interceptor can change between the initial load and the cache load
104	                if let Some(cache) = self
105	                    .demux
106	                    .interceptor
107	                    .load()
108	                    .as_ref()
109	                    .and_then(|i| prefix.get_ingress_cache(&self.demux.face, i))
110	                {
111	                    self.cache.set(cache).ok();
112	                }
113	            }
114	        }
115	        self.cache.get().and_then(|c| c.get_ref().as_ref())
116	    }
117	}
118	
119	impl TransportPeerEventHandler for DeMux {
120	    fn handle_message(&self, mut msg: NetworkMessageMut) -> ZResult<()> {
121	        let _span = tracing::enabled!(tracing::Level::DEBUG).then(|| {
122	            tracing::debug_span!(
123	                "demux",
124	                zid = %self.zid,
125	                src = %self.face
126	            )
127	            .entered()
128	        });
129	
130	        if has_interceptor(&self.interceptor) {
131	            if let Some(interceptor) = self.interceptor.load().as_ref() {
132	                let mut ctx = DeMuxContext {
133	                    demux: self,
134	                    cache: OnceCell::new(),
135	                    expr: OnceCell::new(),
136	                };
137	
138	                match &msg.body {
139	                    NetworkBodyMut::Request(request) => {
140	                        let request_id = request.id;
141	                        let qos = request.ext_qos;
142	                        if !interceptor.intercept(&mut msg, &mut ctx) {
143	                            // request was blocked by an interceptor, we need to send response final to avoid timeout error
144	                            self.face
145	                                .state
146	                                .primitives
147	                                .send_response_final(&mut ResponseFinal {
148	                                    rid: request_id,
149	                                    ext_qos: qos,
150	                                    ext_tstamp: None,
151	                                });
152	                            return Ok(());
153	                        }
154	                    }
155	                    NetworkBodyMut::Interest(interest) => {
156	                        let interest_id = interest.id;
157	                        if !interceptor.intercept(&mut msg, &mut ctx) {
158	                            // request was blocked by an interceptor, we need to send declare final to avoid timeout error
159	                            self.face.state.primitives.send_declare(RoutingContext::new(
160	                                &mut Declare {
161	                                    interest_id: Some(interest_id),
162	                                    ext_qos: ext::QoSType::DECLARE,
163	                                    ext_tstamp: None,
164	                                    ext_nodeid: ext::NodeIdType::DEFAULT,
165	                                    body: DeclareBody::DeclareFinal(DeclareFinal),
166	                                },
167	                            ));
168	                            return Ok(());
169	                        }
170	                    }
171	                    _ => {
172	                        if !interceptor.intercept(&mut msg, &mut ctx) {
173	                            return Ok(());
174	                        }
175	                    }
176	                };
177	            }
178	        }
179	
180	        match msg.body {
181	            NetworkBodyMut::Push(m) => self.face.send_push(m, msg.reliability),
182	            NetworkBodyMut::Declare(m) => self.face.send_declare(m),
183	            NetworkBodyMut::Interest(m) => self.face.send_interest(m),
184	            NetworkBodyMut::Request(m) => self.face.send_request(m),
185	            NetworkBodyMut::Response(m) => self.face.send_response(m),
186	            NetworkBodyMut::ResponseFinal(m) => self.face.send_response_final(m),
187	            NetworkBodyMut::OAM(m) => {
188	                if self.transport.is_none() {
189	                    bail!("Received network OAM from face w/o transport");
190	                }
191	
192	                let mut declares = vec![];
193	                let ctrl_lock = zlock!(self.face.tables.ctrl_lock);
194	                let mut wtables = zwrite!(self.face.tables.tables);
195	                let tables = &mut *wtables;
196	
197	                let ctx = DispatcherContext {
198	                    tables_lock: &self.face.tables,
199	                    tables: &mut tables.data,
200	                    src_face: &mut self.face.state.clone(),
201	                    send_declare: &mut |p, m| declares.push((p.clone(), m)),
202	                };
203	
204	                let (owner_hat, other_hats) = tables
205	                    .hats
206	                    .partition_mut(&self.face.state.region)
207	                    .expect("face region should have a corresponding hat");
208	
209	                owner_hat.handle_oam(
210	                    ctx,
211	                    m,
212	                    other_hats.map(|hat| &mut **hat as &mut dyn HatTrait),
213	                )?;
214	
215	                drop(wtables);
216	                drop(ctrl_lock);
217	
218	                for (p, m) in declares {
219	                    m.with_mut(|m| p.send_declare(m));
220	                }
221	            }
222	        }
223	
224	        Ok(())
225	    }
226	
227	    fn new_link(&self, _link: Link) {}
228	
229	    fn del_link(&self, _link: Link) {}
230	
231	    fn closed(&self) {
232	        self.face.send_close();
233	    }
234	
235	    fn as_any(&self) -> &dyn Any {
236	        self
237	    }
238	}
