37	impl Namespace {
38	    pub(crate) fn new(namespace: OwnedNonWildKeyExpr, primitives: Arc<Face>) -> Self {
39	        Namespace {
40	            namespace,
41	            primitives,
42	        }
43	    }
44	
45	    fn handle_namespace_egress(&self, key_expr: &mut WireExpr, new_keyexpr_declare: bool) {
46	        if key_expr.scope == EMPTY_EXPR_ID || new_keyexpr_declare {
47	            // non - optimized ke
48	            let key = key_expr.suffix.as_ref();
49	            key_expr.suffix = std::borrow::Cow::Owned(match key.is_empty() {
50	                true => self.namespace.as_str().to_owned(), // a case where only a namespace was declared
51	                false => self.namespace.as_str().to_owned() + "/" + key,
52	            });
53	        }
54	        // already optimized ke, given that all of the ke declarations pass through this functions
55	        // it should already account for namespace prefix, and thus no extra processing is needed
56	    }
57	
58	    fn handle_declare_egress(&self, msg: &mut zenoh_protocol::network::Declare) {
59	        match &mut msg.body {
60	            DeclareBody::DeclareKeyExpr(m) => {
61	                self.handle_namespace_egress(&mut m.wire_expr, true);
62	            }
63	            DeclareBody::UndeclareKeyExpr(_) => {}
64	            DeclareBody::DeclareSubscriber(m) => {
65	                self.handle_namespace_egress(&mut m.wire_expr, false);
66	            }
67	            DeclareBody::UndeclareSubscriber(_) => {}
68	            DeclareBody::DeclareQueryable(m) => {
69	                self.handle_namespace_egress(&mut m.wire_expr, false);
70	            }
71	            DeclareBody::UndeclareQueryable(m) => {
72	                self.handle_namespace_egress(&mut m.ext_wire_expr.wire_expr, false);
73	            }
74	            DeclareBody::DeclareToken(m) => {
75	                self.handle_namespace_egress(&mut m.wire_expr, false);
76	            }
77	            DeclareBody::UndeclareToken(_) => {}
78	            DeclareBody::DeclareFinal(_) => {}
79	        }
80	    }
81	}
