129	pub(crate) struct ENamespace {
130	    namespace: OwnedNonWildKeyExpr,
131	    primitives: Arc<dyn EPrimitives + Send + Send>,
132	    incomplete_ingress_keyexpr_declarations: RwLock<HashMap<u16, String>>,
133	    blocked_subscribers: RwLock<HashSet<u32>>,
134	    blocked_queryables: RwLock<HashSet<u32>>,
135	    blocked_tokens: RwLock<HashSet<u32>>,
136	    blocked_interests: RwLock<HashSet<u32>>,
137	}
138	
139	impl ENamespace {
140	    pub(crate) fn new(
141	        namespace: OwnedNonWildKeyExpr,
142	        primitives: Arc<dyn EPrimitives + Send + Sync>,
143	    ) -> Self {
144	        ENamespace {
145	            namespace,
146	            primitives,
147	            incomplete_ingress_keyexpr_declarations: HashMap::new().into(),
148	            blocked_subscribers: HashSet::new().into(),
149	            blocked_queryables: HashSet::new().into(),
150	            blocked_tokens: HashSet::new().into(),
151	            blocked_interests: HashSet::new().into(),
152	        }
153	    }
154	
155	    fn handle_namespace_ingress(&self, key_expr: &mut WireExpr, message_id: Option<u16>) -> bool {
156	        if key_expr.scope != EMPTY_EXPR_ID && key_expr.mapping == Mapping::Receiver {
157	            return true;
158	        }
159	        if key_expr.scope != EMPTY_EXPR_ID {
160	            // mapping sender
161	            // optimized ke
162	            match zread!(self.incomplete_ingress_keyexpr_declarations).get(&key_expr.scope) {
163	                Some(head) => {
164	                    // if it references an incomplete keyexpr, we concatenate them and verify again as fully non-optimized ke
165	                    if key_expr.suffix.is_empty() {
166	                        return false;
167	                    }
168	                    key_expr.scope = EMPTY_EXPR_ID;
169	                    key_expr.suffix = (head.clone() + key_expr.suffix.as_ref()).into();
170	                    return self.handle_namespace_ingress(key_expr, None);
171	                }
172	                None => return true,
173	            }
174	        }
175	        let key = key_expr.suffix.as_ref();
176	        let ke = unsafe { keyexpr::from_str_unchecked(key) };
177	        if let Some(tail) = ke.strip_nonwild_prefix(&self.namespace) {
178	            key_expr.suffix = tail.as_str().to_owned().into();
179	
180	            true
181	        } else if let Some(id) = message_id {
182	            if key_expr.mapping == Mapping::Sender {
183	                // ke does not match namespace - but this can be a partial declaration
184	                // we store this ke for checking future keyexprs, referencing it
185	                zwrite!(self.incomplete_ingress_keyexpr_declarations)
186	                    .insert(id, key_expr.suffix.as_ref().to_string());
187	            }
188	            false
189	        } else {
190	            trace!("Rejecting message containing wire expression `{}`, since it does not match namespace `{}`", &key_expr, self.namespace.as_ref());
191	            false
192	        }
193	    }
194	
195	    fn handle_declare_ingress(&self, msg: &mut zenoh_protocol::network::Declare) -> bool {
196	        match &mut msg.body {
197	            DeclareBody::DeclareKeyExpr(m) => {
198	                self.handle_namespace_ingress(&mut m.wire_expr, Some(m.id))
199	            }
200	            DeclareBody::UndeclareKeyExpr(m) => {
201	                zwrite!(self.incomplete_ingress_keyexpr_declarations)
202	                    .remove(&m.id)
203	                    .is_none()
204	            }
205	            DeclareBody::DeclareSubscriber(m) => {
206	                if !self.handle_namespace_ingress(&mut m.wire_expr, None) {
207	                    zwrite!(self.blocked_subscribers).insert(m.id);
208	                    return false;
209	                }
210	                true
211	            }
212	            DeclareBody::UndeclareSubscriber(m) => !zwrite!(self.blocked_subscribers).remove(&m.id),
213	            DeclareBody::DeclareQueryable(m) => {
214	                if !self.handle_namespace_ingress(&mut m.wire_expr, None) {
215	                    zwrite!(self.blocked_queryables).insert(m.id);
216	                    return false;
217	                }
218	                true
219	            }
220	            DeclareBody::UndeclareQueryable(m) => !zwrite!(self.blocked_queryables).remove(&m.id),
221	            DeclareBody::DeclareToken(m) => {
222	                if !self.handle_namespace_ingress(&mut m.wire_expr, None) {
223	                    zwrite!(self.blocked_tokens).insert(m.id);
224	                    return false;
225	                }
226	                true
227	            }
228	            DeclareBody::UndeclareToken(m) => !zwrite!(self.blocked_tokens).remove(&m.id),
229	            DeclareBody::DeclareFinal(_) => true,
230	        }
231	    }
232	
233	    fn handle_interest_ingress(&self, msg: &mut zenoh_protocol::network::Interest) -> bool {
234	        match msg.mode {
235	            InterestMode::Final => !zwrite!(self.blocked_interests).remove(&msg.id),
236	            _ => match &mut msg.wire_expr {
237	                Some(wire_expr) => {
238	                    if !self.handle_namespace_ingress(wire_expr, None) {
239	                        zwrite!(self.blocked_interests).insert(msg.id);
240	                        return false;
241	                    }
242	                    true
243	                }
244	                None => true,
245	            },
246	        }
247	    }
248	}
